5	class ApiService {
6	  static const String baseUrl = 'http://10.0.2.2:8000';
7	  
8	  // Check username availability
9	  static Future<bool> checkUsername(String username) async {
10	    try {
11	      final response = await http.get(
12	        Uri.parse('$baseUrl/api/check-username?username=${Uri.encodeComponent(username)}'),
13	      );
14	      if (response.statusCode == 200) {
15	        return jsonDecode(response.body)['available'] == true;
16	      }
17	      return false;
18	    } catch (e) {
19	      return false;
20	    }
21	  }
22	
23	  // Register user
24	  static Future<bool> register(String username, String password) async {
25	    try {
26	      final response = await http.post(
27	        Uri.parse('$baseUrl/api/register'),
28	        headers: {'Content-Type': 'application/json'},
29	        body: jsonEncode({
30	          'username': username,
31	          'email': '$username@logindemo.com',
32	          'password': password,
33	        }),
34	      );
35	      return response.statusCode == 201;
36	    } catch (e) {
37	      return false;
38	    }
39	  }
40	  
41	  // Login user
42	  static Future<Map<String, dynamic>> login(String username, String password) async {
43	    try {
44	      final response = await http.post(
45	        Uri.parse('$baseUrl/login'),
46	        headers: {
47	          'Content-Type': 'application/json',
48	        },
49	        body: jsonEncode({
50	          'username': username,
51	          'password': password,
52	        }),
53	      );
54	      
55	      final responseData = jsonDecode(response.body);
56	      
57	      if (response.statusCode == 200 && responseData['access_token'] != null) {
58	        // Store JWT token
59	        await _storeToken(responseData['access_token']);
60	      }
61	      
62	      return {
63	        'success': response.statusCode == 200,
64	        'data': responseData,
65	        'statusCode': response.statusCode,
66	      };
67	    } catch (e) {
68	      return {
69	        'success': false,
70	        'error': e.toString(),
71	      };
72	    }
73	  }
74	  
75	  // Get current user profile
76	  static Future<Map<String, dynamic>> getProfile() async {
77	    try {
78	      final token = await _getToken();
79	      final response = await http.get(
80	        Uri.parse('$baseUrl/api/users/me'),
81	        headers: {
82	          'Content-Type': 'application/json',
83	          if (token != null) 'Authorization': 'Bearer $token',
84	        },
85	      );
86	      return {
87	        'success': response.statusCode == 200,
88	        'data': jsonDecode(response.body),
89	        'statusCode': response.statusCode,
90	      };
91	    } catch (e) {
92	      return {
93	        'success': false,
94	        'error': e.toString(),
95	      };
96	    }
97	  }
98	
99	  // Get the token for use in image URLs
100	  static Future<String?> getToken() async => await _getToken();
101	
102	  // Get hello world data
103	  static Future<Map<String, dynamic>> getHello() async {
104	    try {
105	      final token = await _getToken();
106	      
107	      final response = await http.get(
108	        Uri.parse('$baseUrl/api/hello'),
109	        headers: {
110	          'Content-Type': 'application/json',
111	          if (token != null) 'Authorization': 'Bearer $token',
112	        },
113	      );
114	      
115	      return {
116	        'success': response.statusCode == 200,
117	        'data': jsonDecode(response.body),
118	        'statusCode': response.statusCode,
119	      };
120	    } catch (e) {
121	      return {
122	        'success': false,
123	        'error': e.toString(),
124	      };
125	    }
126	  }
127	  
128	  // Store JWT token
129	  static Future<void> _storeToken(String token) async {
130	    final prefs = await SharedPreferences.getInstance();
131	    await prefs.setString('jwt_token', token);
132	  }
133	  
134	  // Get stored JWT token
135	  static Future<String?> _getToken() async {
136	    final prefs = await SharedPreferences.getInstance();
137	    return prefs.getString('jwt_token');
138	  }
139	  
140	  // Check if user is logged in
141	  static Future<bool> isLoggedIn() async {
142	    final token = await _getToken();
143	    return token != null && token.isNotEmpty;
144	  }
145	  
146	  // Logout user
147	  static Future<void> logout() async {
148	    final prefs = await SharedPreferences.getInstance();
149	    await prefs.remove('jwt_token');
150	  }
151	}

