5	class AuthService {
6	  static const String baseUrl = 'http://10.0.2.2:8000';
7	  
8	  Future<String?> login(String username, String password) async {
9	    try {
10	      final response = await http.post(
11	        Uri.parse('$baseUrl/api/login'),
12	        body: 'username=${Uri.encodeComponent(username)}&password=${Uri.encodeComponent(password)}',
13	        headers: {'Content-Type': 'application/x-www-form-urlencoded'},
14	      );
15	
16	      print('Login response status: ${response.statusCode}');
17	      print('Login response body: ${response.body}');
18	      if (response.statusCode == 200) {
19	        final Map<String, dynamic> responseData = jsonDecode(response.body);
20	        final String token = responseData['access_token'];
21	        
22	        // Store the token securely using SharedPreferences
23	        final prefs = await SharedPreferences.getInstance();
24	        await prefs.setString('jwt_token', token);
25	        
26	        return token;
27	      } else {
28	        // Handle login failure
29	        return null;
30	      }
31	    } catch (e) {
32	      // Handle network or other errors
33	      print('Login error: $e');
34	      return null;
35	    }
36	  }
37	
38	  Future<void> logout() async {
39	    final prefs = await SharedPreferences.getInstance();
40	    await prefs.remove('jwt_token');
41	  }
42	
