44	    final prefs = await SharedPreferences.getInstance();
45	    return prefs.getString('jwt_token') != null;
46	  }
47	
48	  Future<String?> getUsername() async {
49	    final prefs = await SharedPreferences.getInstance();
50	    return prefs.getString('username');
