13	class _RegisterScreenState extends State<RegisterScreen> {
14	  final _usernameController = TextEditingController();
15	  final _passwordController = TextEditingController();
16	
17	  String _usernameError = '';
18	  String _passwordError = '';
19	  String _generalError = '';
20	  bool _usernameAvailable = false;
21	  bool _checkingUsername = false;
22	  bool _isLoading = false;
23	
24	  Timer? _debounce;
25	
26	  @override
27	  void dispose() {
28	    _debounce?.cancel();
29	    _usernameController.dispose();
30	    _passwordController.dispose();
31	    super.dispose();
32	  }
33	
34	  void _onUsernameChanged(String value) {
35	    if (_debounce?.isActive ?? false) _debounce!.cancel();
36	    setState(() { _usernameAvailable = false; _usernameError = ''; });
37	    if (value.trim().length < 3) {
38	      setState(() => _usernameError = value.isEmpty ? '' : 'At least 3 characters');
39	      return;
40	    }
41	    setState(() => _checkingUsername = true);
42	    _debounce = Timer(const Duration(milliseconds: 600), () async {
43	      final available = await ApiService.checkUsername(value.trim());
44	      if (mounted) {
45	        setState(() {
46	          _checkingUsername = false;
47	          _usernameAvailable = available;
48	          _usernameError = available ? '' : 'Username already taken';
49	        });
50	      }
51	    });
52	  }
53	
54	  void _onPasswordChanged(String value) {
55	    setState(() {
56	      _passwordError = (value.isNotEmpty && value.length < 12)
57	          ? 'Minimum 12 characters'
58	          : '';
59	    });
60	  }
61	
62	  void _next() {
63	    final username = _usernameController.text.trim();
64	    final password = _passwordController.text;
65	
66	    if (username.isEmpty || password.isEmpty) {
67	      setState(() => _generalError = 'Please fill in all fields');
68	      return;
69	    }
70	    if (!_usernameAvailable) {
71	      setState(() => _usernameError = 'Choose an available username');
72	      return;
73	    }
74	    if (password.length < 12) {
75	      setState(() => _passwordError = 'Minimum 12 characters');
76	      return;
77	    }
78	
79	    if (mounted) {
80	      Navigator.of(context).push(
81	        MaterialPageRoute(
82	          builder: (_) => DobScreen(username: username, password: password),
83	        ),
84	      );
85	    }
86	  }
